import type { AdminSettings, ChainKey, HistoryItem } from "./types";

const defaultAdmin: AdminSettings = {
  feeBps: Number(import.meta.env.VITE_DEFAULT_APP_FEE_BPS ?? 30),
  feeRecipient: import.meta.env.VITE_DEFAULT_APP_FEE_RECIPIENT ?? "",
