      </div>
      <aside className="route-card"><div className="route-head"><span><i /> BEST ROUTE</span><small>{quote.data ? "LIVE" : "PREVIEW"}</small></div><h3>Relay Fast Bridge</h3><div className="route-visual"><div><ChainIcon chain={fromChain} size="lg" /><small>{fromChain.name}</small></div><div className="route-line"><i /><Zap size={17} /><i /></div><div><ChainIcon chain={toChain} size="lg" /><small>{toChain.name}</small></div></div><div className="route-metrics"><div><Clock3 /><span>Estimasi waktu<b>~8 detik</b></span></div><div><CircleDollarSign /><span>Network fee<b>{store.sponsored ? "$0 sponsored" : "~$0.02"}</b></span></div><div><Gauge /><span>Price impact<b className="good">&lt; 0.01%</b></span></div></div><div className="route-footer"><span><Check size={14} /> Recommended</span><button onClick={() => toast.info("Relay mengembalikan satu rute terbaik untuk pasangan ini")}>Lihat detail <ArrowUpRight size={14} /></button></div></aside>
    </section>
