function DashboardPage() {
  const admin = useAppStore((s) => s.admin), save = useAppStore((s) => s.saveAdmin), reset = useAppStore((s) => s.resetAdmin), history = useAppStore((s) => s.history);
  const [draft, setDraft] = useState<AdminSettings>(admin);
  const spent = history.reduce((sum, item) => sum + Number(item.fee || 0), 0);
  function update(key: keyof AdminSettings, value: string) { setDraft({ ...draft, [key]: key === "feeRecipient" ? value : Number(value) }); }
  function submit() { if (draft.feeBps < 30 || draft.feeBps > 50) return toast.error("App fee harus antara 0,3%–0,5%"); if (draft.feeRecipient && !/^0x[a-fA-F0-9]{40}$/.test(draft.feeRecipient)) return toast.error("Alamat fee recipient tidak valid"); save(draft); toast.success("Pengaturan operator disimpan di browser ini"); }
  return <main className="page"><PageHead eyebrow="OPERATOR CONSOLE" title="Dashboard" text="Kelola monetisasi dan sponsorship. Pengaturan ini bersifat lokal pada perangkat ini." /><div className="notice"><Activity /> <span><b>Static operator mode</b> Auto top-up membutuhkan keeper eksternal; tidak ada secret atau scheduler yang berjalan di browser.</span></div><div className="metric-grid"><div><span>Accrued App Fees</span><b>{money(spent)}</b><small>Berdasarkan riwayat lokal</small></div><div><span>Sponsorship Balance</span><b>—</b><small className="warning-text">Proxy belum mengirim data</small></div><div><span>App Fee Aktif</span><b>{(admin.feeBps / 100).toFixed(2)}%</b><small>Per transaksi</small></div></div><div className="dashboard-grid"><section className="panel form-panel"><div className="panel-title"><span><CircleDollarSign /></span><div><h2>App Fee Settings</h2><p>Diterapkan pada quote Relay berikutnya</p></div></div><label>Persentase fee <span>0,3%–0,5%</span><div className="input-suffix"><input type="number" min="0.3" max="0.5" step="0.05" value={draft.feeBps / 100} onChange={(e) => update("feeBps", String(Number(e.target.value) * 100))} /><i>%</i></div></label><label>Fee recipient (EVM)<input placeholder="0x…" value={draft.feeRecipient} onChange={(e) => update("feeRecipient", e.target.value)} /></label><div className="form-actions"><button className="small-primary" onClick={submit}>Simpan Pengaturan</button><button className="ghost-btn" onClick={() => { reset(); setDraft({ ...admin, feeBps: 30 }); }}>Reset</button></div></section><section className="panel form-panel"><div className="panel-title"><span><Fuel /></span><div><h2>Sponsorship</h2><p>Batas belanja fee tujuan</p></div></div><label>Max subsidization per swap<div className="input-suffix"><input type="number" value={draft.sponsorshipCap} onChange={(e) => update("sponsorshipCap", e.target.value)} /><i>USDC</i></div></label><div className="two-inputs"><label>Low threshold<input type="number" value={draft.threshold} onChange={(e) => update("threshold", e.target.value)} /></label><label>Top-up target<input type="number" value={draft.target} onChange={(e) => update("target", e.target.value)} /></label></div><button className="outline-btn" onClick={() => toast.info("Top-up memerlukan wallet Base, USDC, dan konfigurasi solver Relay yang tervalidasi.")}>Review Manual Top-up <ArrowUpRight /></button></section></div></main>;
}

function DocsPage() {
  const sections = [
    ["quick-start", "Quick Start", "Hubungkan wallet EVM, pilih aset asal dan tujuan, masukkan jumlah, lalu tinjau quote Relay sebelum signing."],
    ["wallets", "Wallets", "Wallet injected seperti MetaMask didukung pada mode browser. Rute Solana memerlukan adapter Solana dan alamat tujuan yang kompatibel."],
    ["app-fees", "App Fees", "Masbro meneruskan appFees pada options quote. Fee operator dibatasi 30–50 bps dan selalu ditampilkan sebelum konfirmasi."],
    ["sponsorship", "Fee Sponsorship", "Aktif hanya lewat proxy aman. Request memakai subsidizeFees dan maxSubsidizationAmount dalam unit USDC 6 desimal."],
    ["gasless", "Gasless Limitations", "Sponsorship tujuan tidak selalu menanggung origin gas. Approval token pertama dan rent Solana dapat tetap diperlukan."],
    ["auto-topup", "Auto Top-up", "Jalankan keeper eksternal yang memantau balance, menerapkan threshold dan daily cap, mengirim Base USDC dengan credit calldata resmi, lalu memverifikasi receipt."],
    ["security", "Security", "Jangan pernah menaruh Relay API key, signer key, seed phrase, atau private key dalam VITE_*. Semua variabel Vite dapat dibaca publik."],
    ["environment", "Environment", "Gunakan VITE_RELAY_SOURCE, VITE_RELAY_API_URL, VITE_RELAY_PROXY_URL, VITE_WALLETCONNECT_PROJECT_ID, VITE_DEFAULT_APP_FEE_RECIPIENT, dan VITE_SPONSORSHIP_WALLET."],
  ];
  return <main className="page docs-page"><PageHead eyebrow="DOCUMENTATION" title="Masbro Docs" text="Panduan integrasi Relay, fee sponsorship, keamanan, dan operasi produksi." /><div className="docs-layout"><aside className="docs-nav">{sections.map(([id, title]) => <a key={id} href={`#${id}`}>{title}</a>)}</aside><div className="docs-content">{sections.map(([id, title, text], index) => <section id={id} key={id}><span>0{index + 1}</span><h2>{title}</h2><p>{text}</p>{id === "quick-start" && <pre><code>{`const client = getClient()\nawait client.actions.getQuote({\n  chainId, toChainId, amount,\n  tradeType: "EXACT_INPUT"\n})`}</code></pre>}{id === "security" && <a href="https://docs.relay.link" target="_blank" rel="noreferrer">Buka dokumentasi Relay <ExternalLink /></a>}</section>)}</div></div></main>;
}

function Footer() { return <footer><div><span className="brand"><span className="brand-mark"><Sparkles size={16} /></span>Masbro <b>Swap</b></span><p>Swap Antar Chain Sekejap, Gas Paling Hemat.</p></div><div><span>BUILT ON</span><b><Zap size={15} /> Relay Protocol</b></div><small>© 2026 Masbro Swap v1 · Non-custodial</small></footer>; }

export default function App() {
  const [wallet, setWallet] = useState<WalletState | null>(null), [walletModal, setWalletModal] = useState(false);
  const location = useLocation();
  useEffect(() => { window.scrollTo({ top: 0, behavior: "smooth" }); }, [location.pathname]);
  async function connectInjected() {
    if (!window.ethereum) { toast.error("Wallet browser tidak ditemukan", { description: "Pasang MetaMask atau wallet EVM kompatibel." }); return; }
    try { const accounts = await window.ethereum.request({ method: "eth_requestAccounts" }) as string[]; const chainHex = await window.ethereum.request({ method: "eth_chainId" }) as string; if (accounts[0]) { setWallet({ address: accounts[0], chainId: Number(chainHex) }); setWalletModal(false); toast.success("Wallet terhubung"); } } catch { toast.error("Koneksi wallet dibatalkan"); }
  }
  function connect() { setWalletModal(true); }
  const routes = useMemo(() => <Routes><Route path="/" element={<SwapPage wallet={wallet} connect={connect} />} /><Route path="/history" element={<HistoryPage />} /><Route path="/dashboard" element={<DashboardPage />} /><Route path="/docs" element={<DocsPage />} /><Route path="*" element={<Navigate to="/" replace />} /></Routes>, [wallet]);
  return <div className="app-shell"><div className="ambient ambient-one" /><div className="ambient ambient-two" /><Header wallet={wallet} connect={connect} disconnect={() => { setWallet(null); toast.info("Wallet diputuskan"); }} />{routes}<Footer />{walletModal && <ModalShell title="Connect wallet" onClose={() => setWalletModal(false)}><p className="modal-copy">Pilih wallet untuk mulai swap lintas chain.</p><button className="wallet-option" onClick={connectInjected}><span className="wallet-logo">◆</span><span><b>Browser Wallet</b><small>MetaMask, Rabby, Coinbase & lainnya</small></span><ArrowRight /></button><button className="wallet-option" onClick={() => toast.info("Adapter Solana perlu dikonfigurasi dengan public RPC dan wallet provider.")}><span className="wallet-logo sol">S</span><span><b>Solana Wallet</b><small>Phantom, Solflare</small></span><ArrowRight /></button><p className="wallet-terms"><ShieldCheck /> Masbro tidak pernah mengakses seed phrase atau private key.</p></ModalShell>}</div>;
}

