.notice { margin:-10px 0 22px;padding:12px 14px;}.notice span { display:flex;flex-direction:column;}.notice b { color:#bcecf1;font-size:10px;}.metric-grid { display:grid;grid-template-columns:repeat(3,1fr);gap:12px;margin-bottom:16px;}.metric-grid>div { border:1px solid #ffffff10;background:#111217;border-radius:13px;padding:18px;display:flex;flex-direction:column;gap:7px;}.metric-grid span { color:#777984;font-size:9px;}.metric-grid b { font-size:24px;letter-spacing:-.04em;}.metric-grid small { color:#5e6069;font-size:8px;}.warning-text { color:#f2a95e!important;}.dashboard-grid { display:grid;grid-template-columns:1fr 1fr;gap:16px;}.form-panel { padding:21px;}.panel-title { display:flex;align-items:center;gap:10px;border-bottom:1px solid #ffffff0b;padding-bottom:16px;margin-bottom:17px;}.panel-title>span { width:35px;height:35px;display:grid;place-items:center;border-radius:9px;background:#a855f714;color:#a95bec;}.panel-title svg { width:17px;}.panel-title h2 { margin:0 0 3px;font-size:13px;}.panel-title p { margin:0;color:#686a73;font-size:8px;}.form-panel label { display:flex;flex-direction:column;gap:7px;color:#9799a2;font-size:9px;margin:13px 0;}.form-panel label>span { color:#5d5f68;float:right;}.input-suffix { position:relative;}.input-suffix i { position:absolute;right:11px;top:50%;transform:translateY(-50%);color:#757780;font-style:normal;font-size:9px;}.input-suffix input { padding-right:45px;}.two-inputs { display:grid;grid-template-columns:1fr 1fr;gap:10px;}.form-actions { display:flex;gap:8px;margin-top:17px;}.outline-btn { width:100%;background:transparent;border:1px solid #a855f737;color:#b76cf4;margin-top:15px;}.outline-btn svg { width:14px;}
.docs-layout { display:grid;grid-template-columns:190px 1fr;gap:36px;align-items:start;}.docs-nav { position:sticky;top:100px;display:flex;flex-direction:column;border-left:1px solid #ffffff12;}.docs-nav a { color:#72747e;font-size:10px;padding:8px 15px;}.docs-nav a:hover { color:#c273ff;border-left:1px solid #a855f7;margin-left:-1px;}.docs-content { display:flex;flex-direction:column;gap:14px;}.docs-content section { scroll-margin-top:100px;border:1px solid #ffffff0e;background:#101116;border-radius:13px;padding:22px;position:relative;}.docs-content section>span { position:absolute;right:18px;top:15px;color:#ffffff0b;font-size:30px;font-weight:800;}.docs-content h2 { margin:0 0 9px;font-size:16px;}.docs-content p { color:#858791;font-size:11px;line-height:1.7;margin:0;max-width:680px;}.docs-content pre { background:#08090c;border:1px solid #ffffff0d;border-radius:9px;padding:14px;overflow:auto;color:#c48af8;font-size:10px;margin:15px 0 0;}.docs-content a { display:inline-flex;gap:5px;color:#b66ff1;font-size:10px;margin-top:12px;}.docs-content a svg { width:13px;}
footer { border-top:1px solid #ffffff0b;width:min(1180px,calc(100% - 40px));margin:auto;padding:27px 0 35px;display:flex;align-items:center;justify-content:space-between;color:#62646d;}footer>div:first-child p { font-size:8px;margin:6px 0 0;}footer>div:nth-child(2) { display:flex;flex-direction:column;align-items:center;gap:5px;}footer>div:nth-child(2)>span { font-size:7px;letter-spacing:.14em;}footer>div:nth-child(2)b { display:flex;gap:4px;align-items:center;color:#aaa;font-size:10px;}footer small { font-size:8px;}
.spin { animation:spin 1s linear infinite; }
@keyframes spin { to{transform:rotate(360deg)} } @keyframes fade{from{opacity:0}} @keyframes pop{from{opacity:0;transform:translateY(10px) scale(.98)}}
@media(max-width:760px){
 .header { height:66px; }.header-inner { width:calc(100% - 28px); }.desktop-nav,.relay-status { display:none; }.wallet-btn span { display:none; }.wallet-btn { padding:0 12px; }.mobile-menu { display:grid;place-items:center;border:0;background:transparent;color:#aaa;width:36px;height:36px;cursor:pointer; }.mobile-nav { position:absolute;display:flex;flex-direction:column;top:66px;left:12px;right:12px;background:#121318;border:1px solid #ffffff14;border-radius:12px;padding:8px;box-shadow:0 20px 60px #000; }.mobile-nav a { padding:12px;border-radius:8px;color:#9698a1;display:flex;gap:9px;font-size:12px;}.mobile-nav a.active { background:#a855f715;color:white;}
 .hero { padding:52px 18px 34px; }.hero h1 { font-size:40px; }.hero>p { font-size:12px;line-height:1.6; }.hero-stats { gap:14px;flex-wrap:wrap;}.swap-layout { grid-template-columns:1fr;width:min(500px,calc(100% - 22px));}.swap-card { padding:16px;border-radius:16px;}.route-card { order:2;}.primary-action>svg { position:static;margin:0;}.trust-row { grid-template-columns:1fr;gap:18px;margin-bottom:50px;}.trust-row>div { border-right:0;justify-content:flex-start;padding-left:25%;}.modal-backdrop { align-items:end;padding:0;}.modal { width:100%;max-height:88dvh;border-radius:19px 19px 0 0;padding:20px 18px calc(22px + env(safe-area-inset-bottom));}.modal-wide { width:100%;}
 .page { width:calc(100% - 24px);padding:48px 0 65px;}.page-head h1 { font-size:29px;}.page-head p { line-height:1.6;}.toolbar { align-items:stretch;flex-direction:column;}.toolbar-actions { flex-direction:column;}.small-search { width:100%;}.filters { overflow:auto;}.history-list article { grid-template-columns:10px 1fr 35px;}.history-list article>div:nth-child(3) { display:none;}.metric-grid,.dashboard-grid { grid-template-columns:1fr;}.docs-layout { grid-template-columns:1fr;}.docs-nav { position:static;flex-direction:row;overflow:auto;border-left:0;border-bottom:1px solid #ffffff12;padding-bottom:8px;}.docs-nav a { flex:none;padding:7px 10px;}footer { align-items:flex-start;gap:25px;flex-wrap:wrap;}footer>div:nth-child(2){align-items:flex-start;}footer small{width:100%;}.review-route { grid-template-columns:1fr;gap:10px;}.review-route>svg { transform:rotate(90deg);margin:auto;}
}
@media(prefers-reduced-motion:reduce){*{scroll-behavior:auto!important;animation-duration:.01ms!important;transition-duration:.01ms!important}}

