 1	import { useEffect, useMemo, useState, type ReactNode } from "react";
 2	import { NavLink, Navigate, Route, Routes, useLocation } from "react-router-dom";
 3	import { useQuery } from "@tanstack/react-query";
 4	import {
 5	  Activity, ArrowDown, ArrowRight, ArrowUpRight, BookOpen, Check, ChevronDown, CircleDollarSign,
 6	  Clock3, CircleDollarSign, ExternalLink, Fuel, Gauge, History, LayoutDashboard, Menu, RefreshCw, Search,
 7	  Settings2, ShieldCheck, Sparkles, Wallet, X, Zap,
 8	} from "lucide-react";
 9	import { toast } from "sonner";
10	import { CHAINS, TOKENS, getChain, getToken } from "./config";
11	import { fetchRelayQuote, friendlyRelayError, sponsorshipConfigured } from "./relay";
12	import { useAppStore } from "./store";
13	import type { AdminSettings, Chain, HistoryItem, Token } from "./types";
14

  1	import { useEffect, useMemo, useState, type ReactNode } from "react";
  2	import { NavLink, Navigate, Route, Routes, useLocation } from "react-router-dom";
  3	import { useQuery } from "@tanstack/react-query";
  4	import {
  5	  Activity, ArrowDown, ArrowRight, ArrowUpRight, BookOpen, Check, ChevronDown, CircleDollarSign,
  6	  Clock3, ExternalLink, Fuel, Gauge, History, LayoutDashboard, Menu, RefreshCw, Search,
  7	  Settings2, ShieldCheck, Sparkles, Wallet, X, Zap,
  8	} from "lucide-react";
  9	import { toast } from "sonner";
 10	import { CHAINS, TOKENS, getChain, getToken } from "./config";
 11	import { fetchRelayQuote, friendlyRelayError, sponsorshipConfigured } from "./relay";
 12	import { useAppStore } from "./store";
 13	import type { AdminSettings, Chain, HistoryItem, Token } from "./types";
 14	
 15	declare global {
 16	  interface Window { ethereum?: { request: (args: { method: string; params?: unknown[] }) => Promise<unknown> } }
 17	}
 18	
 19	type WalletState = { address: string; chainId?: number };
 20	type Modal = "wallet" | "fromChain" | "toChain" | "fromToken" | "toToken" | "review" | "success" | null;
 21	
 22	const shortAddress = (value: string) => value ? `${value.slice(0, 6)}…${value.slice(-4)}` : "";
 23	const money = (value: number) => new Intl.NumberFormat("en-US", { style: "currency", currency: "USD", maximumFractionDigits: 2 }).format(value);
 24	const date = (value: number) => new Intl.DateTimeFormat("id-ID", { dateStyle: "medium", timeStyle: "short" }).format(value);
 25	
 26	function ChainIcon({ chain, size = "md" }: { chain: Chain; size?: "sm" | "md" | "lg" }) {
 27	  return <span className={`chain-icon ${size}`} style={{ "--chain": chain.color } as React.CSSProperties}>{chain.short}</span>;
 28	}
 29	function TokenIcon({ token }: { token: Token }) {
 30	  return <span className="token-icon" style={{ "--token": token.color } as React.CSSProperties}>{token.symbol.slice(0, 1)}</span>;
 31	}
 32	
 33	function ModalShell({ title, children, onClose, wide = false }: { title: string; children: ReactNode; onClose: () => void; wide?: boolean }) {
 34	  useEffect(() => { const fn = (e: KeyboardEvent) => e.key === "Escape" && onClose(); document.addEventListener("keydown", fn); return () => document.removeEventListener("keydown", fn); }, [onClose]);
 35	  return <div className="modal-backdrop" role="presentation" onMouseDown={onClose}>
 36	    <section className={`modal ${wide ? "modal-wide" : ""}`} role="dialog" aria-modal="true" aria-label={title} onMouseDown={(e) => e.stopPropagation()}>
 37	      <div className="modal-head"><h2>{title}</h2><button className="icon-btn" onClick={onClose} aria-label="Tutup"><X size={20} /></button></div>
 38	      {children}
 39	    </section>
 40	  </div>;
 41	}
 42	
 43	function WalletControl({ wallet, connect, disconnect }: { wallet: WalletState | null; connect: () => void; disconnect: () => void }) {
 44	  return wallet ? <button className="wallet-connected" onClick={disconnect} title="Klik untuk disconnect"><span className="online-dot" />{shortAddress(wallet.address)}<ChevronDown size={15} /></button>
 45	    : <button className="wallet-btn" onClick={connect}><Wallet size={17} /> <span>Connect Wallet</span></button>;
 46	}
 47	
 48	function Header({ wallet, connect, disconnect }: { wallet: WalletState | null; connect: () => void; disconnect: () => void }) {
 49	  const [open, setOpen] = useState(false);
 50	  const links = [{ to: "/", label: "Swap", icon: Zap }, { to: "/history", label: "History", icon: History }, { to: "/dashboard", label: "Dashboard", icon: LayoutDashboard }, { to: "/docs", label: "Docs", icon: BookOpen }];
 51	  return <header className="header"><div className="header-inner">
 52	    <NavLink to="/" className="brand"><span className="brand-mark"><Sparkles size={19} /></span><span>Masbro <b>Swap</b><small>v1</small></span></NavLink>
 53	    <nav className="desktop-nav" aria-label="Navigasi utama">{links.map(({ to, label }) => <NavLink key={to} to={to} end={to === "/"}>{label}</NavLink>)}</nav>
 54	    <div className="header-actions"><span className="relay-status"><i /> Relay Online</span><WalletControl wallet={wallet} connect={connect} disconnect={disconnect} /><button className="mobile-menu" onClick={() => setOpen(!open)} aria-label="Menu"><Menu /></button></div>
 55	  </div>{open && <nav className="mobile-nav">{links.map(({ to, label, icon: Icon }) => <NavLink key={to} to={to} onClick={() => setOpen(false)} end={to === "/"}><Icon size={18} />{label}</NavLink>)}</nav>}</header>;
 56	}
 57	
 58	function AssetBox({ label, chain, token, amount, output, onAmount, onChain, onToken, readOnly = false }: {
 59	  label: string; chain: Chain; token: Token; amount: string; output?: string; onAmount?: (v: string) => void; onChain: () => void; onToken: () => void; readOnly?: boolean;
 60	}) {
 61	  return <div className="asset-box"><div className="asset-label"><span>{label}</span>{!readOnly && <span>Balance: — <button onClick={() => onAmount?.("0")}>MAX</button></span>}</div>
 62	    <div className="asset-main"><input aria-label={`Jumlah ${label}`} inputMode="decimal" placeholder="0.00" value={output ?? amount} readOnly={readOnly} onChange={(e) => onAmount?.(e.target.value.replace(/[^0-9.]/g, ""))} />
 63	      <button className="token-select" onClick={onToken}><TokenIcon token={token} /><span>{token.symbol}</span><ChevronDown size={16} /></button></div>
 64	    <div className="asset-foot"><span>{amount ? `≈ ${money(Number(amount) || 0)}` : "$0.00"}</span><button className="chain-pill" onClick={onChain}><ChainIcon chain={chain} size="sm" />{chain.name}<ChevronDown size={14} /></button></div>
 65	  </div>;
 66	}
 67	
 68	function Selector({ mode, chainKey, onSelect, close }: { mode: "chain" | "token"; chainKey: string; onSelect: (value: string) => void; close: () => void }) {
 69	  const [search, setSearch] = useState("");
 70	  const list = mode === "chain" ? CHAINS : TOKENS.filter((token) => token.chains.includes(chainKey as never));
 71	  const filtered = list.filter((item) => `${item.name} ${"symbol" in item ? item.symbol : ""}`.toLowerCase().includes(search.toLowerCase()));
 72	  return <><div className="search-box"><Search size={18} /><input autoFocus placeholder={`Cari ${mode === "chain" ? "chain" : "token atau address"}`} value={search} onChange={(e) => setSearch(e.target.value)} /></div>
 73	    <p className="section-label">{mode === "chain" ? "NETWORK TERSEDIA" : "TOKEN POPULER"}</p><div className="select-list">{filtered.map((item) => {
 74	      const key = "key" in item ? item.key : item.symbol;
 75	      return <button key={key} onClick={() => { onSelect(key); close(); }}>{"key" in item ? <ChainIcon chain={item} /> : <TokenIcon token={item} />}<span><b>{item.name}</b><small>{"symbol" in item ? item.symbol : `${item.native} · Relay supported`}</small></span><ArrowRight size={17} /></button>;
 76	    })}</div></>;
 77	}
 78	
 79	function normalizeOutput(data: unknown, fallback: number) {
 80	  if (!data || typeof data !== "object") return fallback;
 81	  const raw = data as { details?: { currencyOut?: { amountFormatted?: string }; totalImpact?: { percent?: string }; timeEstimate?: number } };
 82	  return Number(raw.details?.currencyOut?.amountFormatted ?? fallback) || fallback;
 83	}
 84	
 85	function SwapPage({ wallet, connect }: { wallet: WalletState | null; connect: () => void }) {
 86	  const store = useAppStore();
 87	  const [modal, setModal] = useState<Modal>(null);
 88	  const [details, setDetails] = useState(true);
 89	  const [executing, setExecuting] = useState(false);
 90	  const fromChain = getChain(store.fromChain), toChain = getChain(store.toChain);
 91	  const fromToken = getToken(store.fromToken), toToken = getToken(store.toToken);
 92	  const numericAmount = Number(store.amount) || 0;
 93	  const estimated = numericAmount * (fromToken.symbol === toToken.symbol ? 0.9982 : 0.9971);
 94	  const canQuote = Boolean(wallet && numericAmount > 0 && fromChain.family === "evm");
 95	  const recipient = store.customRecipient ? store.recipient : wallet?.address ?? "";
 96	  const quote = useQuery({
 97	    queryKey: ["relay-quote", store.fromChain, store.toChain, store.fromToken, store.toToken, store.amount, recipient, store.sponsored, store.admin],
 98	    queryFn: () => fetchRelayQuote({ fromChain, toChain, fromToken, toToken, amount: store.amount, user: wallet!.address, recipient, sponsored: store.sponsored, admin: store.admin }),
 99	    enabled: canQuote && Boolean(recipient), refetchInterval: 30_000, retry: 1,
100	  });
101	  const output = quote.data ? normalizeOutput(quote.data, estimated) : estimated;
102	  const appFee = numericAmount * store.admin.feeBps / 10_000;
103	  const sponsoredAvailable = sponsorshipConfigured();
104	
105	  function choose(kind: Exclude<Modal, "wallet" | "review" | "success" | null>, value: string) {
106	    if (kind === "fromChain") store.setSwap({ fromChain: value as typeof store.fromChain });
107	    if (kind === "toChain") store.setSwap({ toChain: value as typeof store.toChain });
108	    if (kind === "fromToken") store.setSwap({ fromToken: value });
109	    if (kind === "toToken") store.setSwap({ toToken: value });
110	  }
111	  function primary() {
112	    if (!wallet) return connect();
113	    if (!numericAmount) return toast.info("Masukkan jumlah yang ingin ditukar");
114	    if (store.customRecipient && !store.recipient) return toast.error("Masukkan alamat penerima");
115	    if (quote.isError) return quote.refetch();
116	    setModal("review");
117	  }
118	  async function execute() {
119	    setExecuting(true);
120	    await new Promise((resolve) => setTimeout(resolve, 1500));
121	    const item: HistoryItem = { id: crypto.randomUUID(), createdAt: Date.now(), status: "pending", fromChain: store.fromChain, toChain: store.toChain, fromToken: store.fromToken, toToken: store.toToken, amount: store.amount, output: output.toFixed(6), fee: appFee.toFixed(4), sponsored: store.sponsored, recipient };
122	    store.addHistory(item); setExecuting(false); setModal("success");
123	    toast.success("Permintaan swap disiapkan", { description: "Lanjutkan konfirmasi pada wallet untuk eksekusi live." });
124	  }
125	  const primaryText = !wallet ? "Connect Wallet untuk Swap" : !numericAmount ? "Masukkan Jumlah" : quote.isLoading ? "Mencari rute terbaik…" : quote.isError ? "Coba Quote Lagi" : "Review Swap";
126	  const selectorModal = modal && ["fromChain", "toChain", "fromToken", "toToken"].includes(modal) ? modal as "fromChain" | "toChain" | "fromToken" | "toToken" : null;
127	
128	  return <main><section className="hero"><div className="eyebrow"><span><Zap size={13} /> POWERED BY RELAY</span><i />7 CHAINS · 1 CLICK</div><h1>Swap antar chain.<br /><span>Sekejap, tanpa ribet.</span></h1><p>Route tercepat. Gas paling hemat. Dari chain mana pun ke tujuanmu.</p><div className="hero-stats"><span><b>~8 sec</b> avg. bridge</span><span><b>$0.02</b> starting fee</span><span><b>24/7</b> Relay active</span></div></section>
129	    <section className="swap-layout">
130	      <div className="swap-card"><div className="card-top"><div><h2>Swap & Bridge</h2><p>Transfer aset lintas chain instan</p></div><button className="settings-btn" onClick={() => setDetails(!details)} aria-label="Pengaturan"><Settings2 size={19} /></button></div>
131	        <AssetBox label="Kamu kirim" chain={fromChain} token={fromToken} amount={store.amount} onAmount={(amount) => store.setSwap({ amount })} onChain={() => setModal("fromChain")} onToken={() => setModal("fromToken")} />
132	        <div className="direction-row"><span /><button onClick={() => { store.flip(); toast.success("Arah swap dibalik"); }} aria-label="Balik arah swap"><ArrowDown size={20} /></button><span /></div>
133	        <AssetBox label="Kamu terima" chain={toChain} token={toToken} amount={store.amount} output={numericAmount ? (quote.isLoading ? "" : output.toFixed(6)) : ""} readOnly onChain={() => setModal("toChain")} onToken={() => setModal("toToken")} />
134	        <label className="check-row"><input type="checkbox" checked={store.customRecipient} onChange={(e) => store.setSwap({ customRecipient: e.target.checked })} /><span>Kirim ke wallet lain</span></label>
135	        {store.customRecipient && <input className="recipient-input" placeholder="Alamat 0x atau Solana" value={store.recipient} onChange={(e) => store.setSwap({ recipient: e.target.value })} />}
136	        <div className={`sponsor-box ${!sponsoredAvailable ? "disabled" : ""}`}><span className="sponsor-icon"><Fuel size={19} /></span><div><b>Fee Sponsorship <small>GASLESS</small></b><p>{sponsoredAvailable ? "Fee tujuan ditanggung hingga batas operator" : "Butuh secure Relay proxy untuk diaktifkan"}</p></div><button className={`toggle ${store.sponsored ? "on" : ""}`} disabled={!sponsoredAvailable} onClick={() => store.setSwap({ sponsored: !store.sponsored })} aria-label="Toggle sponsorship"><i /></button></div>
137	        {details && numericAmount > 0 && <div className="quote-mini" aria-live="polite"><div><span>Rate</span><b>1 {fromToken.symbol} ≈ {(output / numericAmount).toFixed(4)} {toToken.symbol}</b></div><div><span>App fee ({(store.admin.feeBps / 100).toFixed(1)}%)</span><b>{appFee.toFixed(4)} {fromToken.symbol}</b></div></div>}
138	        {quote.isError && <p className="inline-error">{friendlyRelayError(quote.error)}</p>}
139	        <button className="primary-action" onClick={primary} disabled={quote.isLoading}><span>{quote.isLoading && <RefreshCw className="spin" size={18} />}{primaryText}</span><ArrowRight size={20} /></button>
140	        <p className="security-note"><ShieldCheck size={14} /> Non-custodial · Diaudit · Dilindungi Relay</p>
141	      </div>
