23	export async function fetchRelayQuote(input: {
24	  fromChain: Chain;
25	  toChain: Chain;
26	  fromToken: Token;
27	  toToken: Token;
28	  amount: string;
29	  user: string;
30	  recipient: string;
31	  sponsored: boolean;
32	  admin: AdminSettings;
33	}) {
34	  const appFees = input.admin.feeRecipient
35	    ? [{ recipient: input.admin.feeRecipient, fee: input.admin.feeBps.toString() }]
36	    : undefined;
37	  return getClient().actions.getQuote({
38	    chainId: input.fromChain.id,
39	    toChainId: input.toChain.id,
40	    currency: input.fromToken.address,
41	    toCurrency: input.toToken.address,
42	    amount: parseUnits(input.amount, input.fromToken.decimals).toString(),
43	    tradeType: "EXACT_INPUT",
44	    user: input.user,
45	    recipient: input.recipient,
46	    options: {
47	      ...(appFees ? { appFees } : {}),
48	      ...(input.sponsored ? {
49	        subsidizeFees: true,
50	        maxSubsidizationAmount: Math.round(input.admin.sponsorshipCap * 1_000_000).toString(),
51	      } : {}),
52	    },
53	  });
54	}
