56	export function friendlyRelayError(error: unknown) {
57	  const message = error instanceof Error ? error.message : "Quote Relay tidak tersedia.";
58	  if (/route|no quotes|unsupported/i.test(message)) return "Rute ini belum tersedia. Coba token atau chain lain.";
59	  if (/rate|429/i.test(message)) return "Relay sedang sibuk. Quote akan dicoba kembali.";
60	  return message.length > 160 ? "Tidak dapat mengambil quote Relay saat ini. Periksa koneksi dan konfigurasi." : message;
61	}
